SELECT 
  FROM er.tn_cef_spchn sp
 WHERE sp.cef_id   = #{cefId}
   AND sp.claim_no = #{claimNo}
   AND NOW() BETWEEN sp.use_bgng_dt AND sp.use_end_dt
 ORDER BY sp.chn_sn ASC

SELECT 
  FROM er.tn_cef_spchn sp
 WHERE sp.cef_id   = #{cefId}
   AND sp.claim_no = #{claimNo}
   AND sp.chn_sn   = #{chnSn}
   AND NOW() BETWEEN sp.use_bgng_dt AND sp.use_end_dt

SELECT COALESCE(MAX(chn_sn), 0) + 1
  FROM er.tn_cef_spchn
 WHERE cef_id   = #{cefId}
   AND claim_no = #{claimNo}

mapper.update:
UPDATE er.tn_cef_spchn
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE cef_id   = #{cefId}
   AND claim_no = #{claimNo}
   AND chn_sn   = #{chnSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
